// ServiceClass
@Service
// UserServiceClass definition
public class UserService {
    private final UserRepository repository;

    // Constructor injection(Recommended)
    // When there is only 1 constructor, @Autowired can be omitted
    public UserService(UserRepository repository) {
        this.repository = repository;
    }

    // findAllMethod definition
    public List<User> findAll() {
        return repository.findAll();
    }
}

// RepositoryClass
@Repository
// UserRepositoryClass definition
public class UserRepository {
    // findAllMethod definition
    public List<User> findAll() {
        // Database access
        return List.of(new User("Alice"), new User("Bob"));
    }
}

// Controller
@RestController
// UserControllerClass definition
public class UserController {
    private final UserService userService;

    public UserController(UserService userService) {
        this.userService = userService;
    }
    @GetMapping("/users")
    public List<User> getUsers() {
        return userService.findAll();
    }
}

